import{_ as e,H as n,f as s,i as t}from"./chunks/framework.Usbf9s97.js";const u=JSON.parse('{"title":"架构总览","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md","lastUpdated":1779801822000}'),p={name:"guide/architecture.md"};function l(i,a,o,d,r,c){return n(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="架构总览" tabindex="-1">架构总览 <a class="header-anchor" href="#架构总览" aria-label="Permalink to &quot;架构总览&quot;">​</a></h1><p>模板把整套应用拆成三个独立运行的进程：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                       Electron App                         │</span></span>
<span class="line"><span>│                                                            │</span></span>
<span class="line"><span>│   ┌──────────────┐         ┌────────────────────────┐      │</span></span>
<span class="line"><span>│   │  Renderer    │  IPC    │      Main Process      │      │</span></span>
<span class="line"><span>│   │  (Vue 3)     │ ◀────▶  │  (Node.js / Electron)  │      │</span></span>
<span class="line"><span>│   └──────┬───────┘         └──────────┬─────────────┘      │</span></span>
<span class="line"><span>│          │                            │ spawn / supervise  │</span></span>
<span class="line"><span>│          │ HTTP /api/bridge           │                    │</span></span>
<span class="line"><span>│          ▼                            ▼                    │</span></span>
<span class="line"><span>│   ┌────────────────────────────────────────────┐           │</span></span>
<span class="line"><span>│   │       Python Backend (FastAPI + WS)        │           │</span></span>
<span class="line"><span>│   │   /api/bridge   /ws/electron  /health ...  │           │</span></span>
<span class="line"><span>│   └────────────────────────────────────────────┘           │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="三个进程的职责" tabindex="-1">三个进程的职责 <a class="header-anchor" href="#三个进程的职责" aria-label="Permalink to &quot;三个进程的职责&quot;">​</a></h2><h3 id="renderer-渲染端" tabindex="-1">Renderer（渲染端） <a class="header-anchor" href="#renderer-渲染端" aria-label="Permalink to &quot;Renderer（渲染端）&quot;">​</a></h3><ul><li>完整的 Vue 应用，UI / 状态 / 路由都在这里</li><li>通过 <code>window.electron</code>（来自 preload）调用主进程能力</li><li>通过 <code>fetch /api/bridge</code> 直接调用 Python 业务</li><li>不持有 Python URL，启动时向主进程拿一次，断开后重新解析</li></ul><h3 id="main-主进程" tabindex="-1">Main（主进程） <a class="header-anchor" href="#main-主进程" aria-label="Permalink to &quot;Main（主进程）&quot;">​</a></h3><ul><li>创建 BrowserWindow、管理菜单与生命周期</li><li>spawn / 监督 Python 子进程，决定开发态走 venv、生产态走打包好的二进制</li><li>维护 IPC Router：依赖注入容器 + 洋葱模型中间件</li><li>持有 <code>BridgeManager</code>：与 Python 的 WebSocket 反向通道</li><li>把 Python 反向调用分发到合适的 handler（系统对话框、窗口操作等）</li></ul><h3 id="python-backend" tabindex="-1">Python Backend <a class="header-anchor" href="#python-backend" aria-label="Permalink to &quot;Python Backend&quot;">​</a></h3><ul><li>FastAPI 应用，启动后监听 <code>127.0.0.1:47821</code>（端口被占用时自动 +1）</li><li>提供 <code>/api/bridge</code> 让渲染端发起业务调用，按 <code>presenter:method</code> 动态分发</li><li>提供 <code>/ws/electron</code> 让主进程订阅，Python 通过它主动调用 Electron 能力</li><li>守护模式下写 <code>daemon.pid</code> / <code>daemon.version</code> / <code>daemon.port</code>，二次启动会拒绝重复 launch</li></ul><h2 id="启动时序" tabindex="-1">启动时序 <a class="header-anchor" href="#启动时序" aria-label="Permalink to &quot;启动时序&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. npm run dev → electron-vite 启动</span></span>
<span class="line"><span>2. main.js: bootstrap()</span></span>
<span class="line"><span>   ├── PythonService.start()</span></span>
<span class="line"><span>   │   ├── 检查 daemon meta，已存在则复用</span></span>
<span class="line"><span>   │   ├── 否则 spawn python_backend/main.py --daemon</span></span>
<span class="line"><span>   │   └── 轮询 /health 直到 ready</span></span>
<span class="line"><span>   ├── BridgeManager 建立 WS 到 /ws/electron</span></span>
<span class="line"><span>   ├── createWindow() 打开主窗口</span></span>
<span class="line"><span>   └── setupIpc()   注册所有 IPC handler</span></span>
<span class="line"><span>3. Renderer 加载首页</span></span>
<span class="line"><span>   ├── 通过 IPC 拿到 backendUrl</span></span>
<span class="line"><span>   └── 用 PythonBridgeClient 调用 /api/bridge</span></span></code></pre></div><h2 id="关键设计取舍" tabindex="-1">关键设计取舍 <a class="header-anchor" href="#关键设计取舍" aria-label="Permalink to &quot;关键设计取舍&quot;">​</a></h2><h3 id="为什么用-http-而不是纯-ipc" tabindex="-1">为什么用 HTTP 而不是纯 IPC <a class="header-anchor" href="#为什么用-http-而不是纯-ipc" aria-label="Permalink to &quot;为什么用 HTTP 而不是纯 IPC&quot;">​</a></h3><p>IPC 适合短而频繁的状态查询；业务调用如果都走 IPC，主进程会变成「转发器」。HTTP 让渲染端直接和 Python 对话，主进程只关心&quot;Python 还活着吗&quot;。</p><h3 id="为什么主进程还是要持有-websocket" tabindex="-1">为什么主进程还是要持有 WebSocket <a class="header-anchor" href="#为什么主进程还是要持有-websocket" aria-label="Permalink to &quot;为什么主进程还是要持有 WebSocket&quot;">​</a></h3><p>Python 偶尔需要主动通知前端（推送、长任务进度、需要弹窗确认）。直接让 Python 连渲染层会破坏 Electron 的安全模型；主进程做中转，再用 IPC 通知渲染端，符合最小特权原则。</p><h3 id="为什么-python-走守护模式" tabindex="-1">为什么 Python 走守护模式 <a class="header-anchor" href="#为什么-python-走守护模式" aria-label="Permalink to &quot;为什么 Python 走守护模式&quot;">​</a></h3><p>冷启动 PyInstaller 单文件 exe 大约 5 秒。守护模式让二次启动复用驻留进程，启动时间降到约 1 秒。<code>LifecycleManager</code> 在长期空闲后软退出，避免占内存。</p><h2 id="错误模型" tabindex="-1">错误模型 <a class="header-anchor" href="#错误模型" aria-label="Permalink to &quot;错误模型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层</th><th>错误</th><th>处理</th></tr></thead><tbody><tr><td>HTTP</td><td>404 / 500</td><td><code>BridgeApiError(code, message)</code> 抛给前端</td></tr><tr><td>HTTP</td><td>超时</td><td><code>BridgeTimeoutError</code></td></tr><tr><td>WS</td><td>断开</td><td>主进程指数退避重连 1/2/4/8/15s</td></tr><tr><td>Python</td><td>LookupError</td><td>转为 <code>NOT_FOUND</code></td></tr><tr><td>Python</td><td>其他异常</td><td>转为 <code>INTERNAL</code> + 完整 traceback</td></tr></tbody></table><p>更多见 <a href="/electron-python-template/guide/communication">通信通道</a> 与 <a href="/electron-python-template/guide/daemon">守护进程</a>。</p>`,22)])])}const b=e(p,[["render",l]]);export{u as __pageData,b as default};
